nodes.inputs:
param appName = 'HeyAzure'
param environment = 'prod'
param budget = 10
param vnetAddressSpace = [
  '10.10.1.0/24'
]
param subscriptionId = '2e94cd4d-4966-42c2-a622-75ad6bb66038'
param subscriptionLevelTags = {
  engineerEmail: engineerEmail
  ownerEmail: ownerEmail
}
param resourceLevelTags = {
  engineerEmail: engineerEmail
}
param defenderRecommendationExemptions = true
param exemptions = []

param policyDefinitions = [
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/6a664864-e2b5-413e-b930-f11caa132f16'
    policyDefinitionReferenceId: 'managed-environments'
    parameters: policyParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/3234ff41-8bec-40a3-b5cb-109c95f1c8ce'
    policyDefinitionReferenceId: 'virtual-network'
    parameters: policyParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/baa4c6de-b7cf-4b12-b436-6e40ef44c8cb'
    policyDefinitionReferenceId: 'network-security-group'
    parameters: policyParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/818719e5-1338-4776-9a9d-3c31e4df5986'
    policyDefinitionReferenceId: 'log-analytics'
    parameters: policyParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/b4fe1a3b-0715-4c6c-a5ea-ffc33cf823cb'
    policyDefinitionReferenceId: 'storage-blob'
    parameters: storageParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/7bd000e3-37c7-4928-9f31-86c4b77c5c45'
    policyDefinitionReferenceId: 'storage-queue'
    parameters: storageParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/2fb86bf3-d221-43d1-96d1-2434af34eaa0'
    policyDefinitionReferenceId: 'storage-table'
    parameters: storageParameters
  }
  {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/25a70cc8-2bd4-47f1-90b6-1478e4662c96'
    policyDefinitionReferenceId: 'storage-file'
    parameters: storageParameters
  }
]

nodes.snippet:
module identity 'br/public:avm/res/managed-identity/user-assigned-identity:0.2.1' = {
  scope: az.resourceGroup(landingzoneResourceGroupName)
  name: 'lz-serviceConnection'
  params: {
    name: 'id-${appName}-${environment}'
    location: location
    federatedIdentityCredentials: [
      {
        name: 'landingzoneOwner'
        audiences: [
          'api://AzureADTokenExchange'
        ]
        issuer: 'https://token.actions.githubusercontent.com'
        subject: 'repo:${githubOrganizationName}/${githubRepoName}:environment:${environment}'
      }
    ]
  }
}

module rbacLandingzoneOwner 'base/roleAssignments-subscription.bicep' = {
  name: 'lz-rbac-serviceConnection'
  params: {
    principalId: identity.outputs.principalId
    roleDefinitionId: AzureRoles.Owner
    principleType: 'ServicePrincipal'
  }
}

module rbacApplicationReader 'base/roleAssignments-subscription.bicep' = {
  name: 'lz-rbac-applicationReader'
  params: {
    principalId: applicationReaderEntraGroupId
    roleDefinitionId: AzureRoles.Reader
    principleType: 'Group'
  }
}

resource vnet 'Microsoft.Network/virtualNetworks@2024-05-01' = {
  name: 'vnet-${appName}-${environment}'
  location: location
  properties: {
    addressSpace: {
      addressPrefixes: vnetAddressSpace
    }
  }
}

resource GithubRunnersSubnet 'Microsoft.Network/virtualNetworks/subnets@2025-05-01' = {
  name: 'github-runners'
  parent: vnet
  properties: {
    addressPrefixes: [
      GitHubRunnersSubnet
    ]
    delegations: [
      {
        name: 'github-runners'
        properties: {
          serviceName: 'GitHub.Network/networkSettings'
        }
      }
    ]
  }
}

resource GitHubRunnersNetwork 'GitHub.Network/networkSettings@2024-04-02' = {
  name: '${appName}-${environment}'
  location: location
  properties: {
    subnetId: GithubRunnersSubnet.id
    businessId: GitHubOrganizationDatabaseId
  }
}

module configDiagnosticSettings 'base/policyAssignment.bicep' = {
  name: 'lz-config-diagnosticSettings'
  params: {
    name: 'config-diagnosticSettings'
    location: location
    displayName: 'Config Diagnostic Settings'
    identityResourceId: identityResourceId
    policyDefinitionId: diagnosticSettingsPolicyResourceId
    parameters: {
      logAnalytics: {
        value: logAnalyticsResourceId
      }
    }
  }
}

module resourceTagsPolicy 'base/policyAssignment.bicep' = [
  for item in items(resourceLevelTags): {
    name: 'lz-resourceLevelTag-${item.key}'
    params: {
      name: 'Config-ResourceLevelTag-${item.key}'
      location: location
      displayName: 'Config Resource Level Tag: ${item.key}'
      identityResourceId: identityResourceId
      policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/4f9dc7db-30c1-420c-b61a-e1d640128d26'
      parameters: {
        tagName: {
          value: item.key
        }
        tagValue: {
          value: item.value
        }
      }
    }
  }
]

module subscriptionTagsPolicy 'base/policyAssignment.bicep' = [
  for item in items(subscriptionLevelTags): {
    name: 'lz-subscriptionLevelTag-${item.key}'
    params: {
      name: 'Config-SubscriptionLevelTag-${item.key}'
      location: location
      displayName: 'Config Subscription Level Tag: ${item.key}'
      identityResourceId: identityResourceId
      policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/61a4d60b-7326-440e-8051-9f94394d4dd1'
      parameters: {
        tagName: {
          value: item.key
        }
        tagValue: {
          value: item.value
        }
      }
    }
  }
]

module customExemption 'base/policyExemption.bicep' = [
  for item in exemptions: {
    params: {
      description: item.clarifications
      policyAssignmentId: item.policyToExclude
      policyDefinitionReferenceIds: item.referenceId
      policyExemptionName: 'lzparam-${split(item.policyToExclude, '/')[8]}'
    }
  }
]

module defenderForCloud 'base/policyExemption.bicep' = if (defenderRecommendationExemptions) {
  name: 'lz-policyExemption-defenderForCloud'
  params: {
    policyExemptionName: 'not applicable reccomendations'
    description: ''
    policyAssignmentId: '${subscription().id}/providers/Microsoft.Authorization/policyAssignments/SecurityCenterBuiltIn'
    policyDefinitionReferenceIds: defenderForCloudExemptions
  }
}

module diagSettingsPolicyExemption 'base/policyExemption.bicep' = if (diagSettingsExemption) {
  name: 'lz-policyExemption-diagSettings'
  dependsOn: [configDiagnosticSettings]
  params: {
    policyExemptionName: 'default'
    description: 'Opted out of automatic diagnostic settings configuration.'
    policyAssignmentId: '${subscription().id}/providers/Microsoft.Authorization/policyAssignments/config-diagnosticSettings'
    policyDefinitionReferenceIds: []
  }
}

module containerAppEnvironment 'base/managedEnvironments.bicep' = {
  params: {
    appName: appName
    environment: environment
    location: location
  }
}

module automationJobs 'base/jobs-cron.bicep' = [
  for item in items(PowerShellJobs): {
    name: 'cron-${item.key}'
    params: {
      environment: environment!
      location: location
      environmentId: containerAppEnvironment.outputs.environmentResourceId
      userAssignedIdentityResourceId: identityResourceId
      jobName: item.key
      userAssignedIdentityClientId: identityClientId
      containerEnvironmentVariables: item.value.variables
      GitHubOrganizationName: GitHubOrganizationName!
    }
  }
]

module actionGroup 'base/actionGroup.bicep' = {
  name: 'lz-actionGroup-notify'
  params: {
    email: engineerEmail
  }
}

module healthAlert 'base/ActivityLogAlerts.bicep' = {
  name: 'lz-health-alert'
  params: {
    actionGroupId: actionGroup.outputs.resourceId
  }
}

module logAnalytics 'base/logAnalyticsWorkspace.bicep' = {
  name: 'lz-logAnalytics'
  params: {
    appName: appName
    environment: environment
    location: location
  }
}

resource budget 'Microsoft.Consumption/budgets@2024-08-01' = {
  #disable-next-line use-stable-resource-identifiers
  name: 'set-by-create-landingzone-${startDate}'
  properties: {
    amount: budgetAmount
    category: 'Cost'
    timeGrain: 'Monthly'
    timePeriod: {
      startDate: startDate
    }
    notifications: {
      abc: {
        contactEmails: []
        enabled: true
        operator: 'GreaterThanOrEqualTo'
        threshold: 100
        thresholdType: 'Forecasted'
        locale: 'en-gb'
        contactGroups: [
          actionGroupResourceId
        ]
      }
    }
  }
}

resource notifications 'Microsoft.Security/securityContacts@2023-12-01-preview' = {
  name: 'default'
  properties: {
    isEnabled: true
    notificationsSources: [
      {
        sourceType: 'Alert'
        minimalSeverity: 'Low'
      }
    ]
    notificationsByRole: {
      state: 'On'
      roles: [
        'Owner'
        'Contributor'
      ]
    }
    emails: engineerEmail
  }
}

resource GraphAggregatorService 'Microsoft.Graph/servicePrincipals@v1.0' existing = {
  appId: '00000003-0000-0000-c000-000000000000'
}

resource appRole 'Microsoft.Graph/appRoleAssignedTo@v1.0' = {
  appRoleId: appRoleId
  principalId: principalId
  resourceId: GraphAggregatorService.id
}

resource policyDefinition 'Microsoft.Authorization/policyDefinitions@2025-03-01' = {
  name: policyName
  properties: policyProperties
}

resource initiative 'Microsoft.Authorization/policySetDefinitions@2025-03-01' = {
  name: shortenPolicyName
  properties: {
    displayName: displayName
    policyDefinitions: setDefinitions
  }
}

resource assignment 'Microsoft.Authorization/policyAssignments@2024-04-01' = {
  name: shortenPolicyName
  location: location
  properties: {
    policyDefinitionId: initiative.id
    displayName: displayName
  }
}

resource managementGroup 'Microsoft.Management/managementGroups@2024-02-01-preview' = {
  name: managementGroupName
  scope: tenant()
  properties: {
    displayName: managementGroupName
    details: {
      parent: {
        id: parentManagementGroupId
      }
    }
  }
}

resource managementGroup 'Microsoft.Management/managementGroups/settings@2024-02-01-preview' = {
  name: '${tenant().tenantId}/default'
  scope: tenant()
  properties: {
    defaultManagementGroup: '/providers/Microsoft.Management/managementGroups/${defaultManagementGroup}'
    requireAuthorizationForGroupCreation: requireAuthorizationForGroupCreation
  }
}

resource customRole 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: guid(roleName, environment)
  properties: {
    roleName: '${roleName} - ${environment}'
    assignableScopes: [
      managementGroup().id
    ]
    permissions: [
      {
        actions: actions
      }
    ]
  }
}

resource rbacAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(roleDefinitionId, managementGroup().id, principalId)
  properties: {
    principalId: principalId
    roleDefinitionId: roleDefinitionId
    principalType: principalType
  }
}

resource rbacAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(roleDefinitionId, principalId, subscription().id)
  properties: {
    principalId: principalId
    roleDefinitionId: roleDefinitionId
    principalType: principleType
  }
}

resource notifyEngineer 'Microsoft.Insights/actionGroups@2024-10-01-preview' = {
  name: 'ag-notify-engineer'
  location: 'global'
  properties: {
    enabled: true
    groupShortName: 'engineer'
    emailReceivers: [
      {
        name: 'landing zone engineer'
        emailAddress: email
      }
    ]
  }
}

resource ActivityLogAlert 'Microsoft.Insights/activityLogAlerts@2020-10-01' = {
  name: 'alert-Azure-health'
  location: 'global'
  properties: {
    enabled: true
    scopes: [
      subscription().id
    ]
    actions: {
      actionGroups: [
        {
          actionGroupId: actionGroupId
        }
      ]
    }
    condition: {
      allOf: [
        {
          field: 'category'
          equals: 'Recommendation'
        }
        {
          field: 'operationName'
          equals: 'Microsoft.Advisor/recommendations/available/action'
        }
        {
          field: 'properties.recommendationType'
          equals: '242639fd-cd73-4be2-8f55-70478db8d1a5'
        }
      ]
    }
  }
}

resource logAnalytics 'Microsoft.OperationalInsights/workspaces@2025-07-01' = {
  name: 'la-${appName}-${environment}'
  location: location
  properties: {
    retentionInDays: 30
    sku: {
      name: 'PerGB2018'
    }
  }
}

resource appEnv 'Microsoft.App/managedEnvironments@2025-10-02-preview' = {
  name: 'cae-${appName}-${environment}'
  location: location
  properties: {
    publicNetworkAccess: 'Disabled'
    workloadProfiles: [
      {
        name: 'Consumption'
        workloadProfileType: 'Consumption'
      }
    ]
    appLogsConfiguration: {
      destination: 'azure-monitor'
    }
  }
}

resource job 'Microsoft.App/jobs@2025-10-02-preview' = {
  name: 'cron-${automationJob}'
  location: location
  identity: {
    type: 'UserAssigned'
    userAssignedIdentities: {
      '${userAssignedIdentityResourceId}': {}
    }
  }
  properties: {
    environmentId: environmentId
    workloadProfileName: 'Consumption'
    configuration: {
      replicaTimeout: 300
      triggerType: 'Schedule'
      scheduleTriggerConfig: {
        cronExpression: cronExpression
        parallelism: 1
        replicaCompletionCount: 1
      }
    }
    template: {
      containers: [
        {
          image: image
          imageType: 'ContainerImage'
          name: automationJob
          args: [
            '${jobName}.ps1'
          ]
          resources: {
            cpu: json('0.5')
            memory: '1Gi'
          }
          env: vars
        }
      ]
    }
  }
}

resource policyAssignment 'Microsoft.Authorization/policyAssignments@2025-03-01' = {
  name: name
  location: location
  identity: {
    type: 'UserAssigned'
    userAssignedIdentities: {
      '${identityResourceId}': {}
    }
  }
  properties: {
    displayName: displayName
    parameters: parameters
    policyDefinitionId: policyDefinitionId
  }
}

resource policyExemption 'Microsoft.Authorization/policyExemptions@2024-12-01-preview' = {
  name: policyExemptionName
  properties: {
    exemptionCategory: 'Waiver'
    policyAssignmentId: policyAssignmentId
    policyDefinitionReferenceIds: policyDefinitionReferenceIds
    description: description
  }
}
